1234	\subsection*{The away-localisation pullback isomorphism}
1235	
1236	\begin{definition}
1237	
1238	\leanok
1239	[Pullback of two principal opens of \(\Spec A\)]
1240	  \label{def:gr_away_pullback_iso}
1241	  \lean{AlgebraicGeometry.Grassmannian.awayPullbackIso}
1242	  \uses{lem:mathlib_pullbackSpecIso, lem:mathlib_isLocalization_away_mul, lem:mathlib_isLocalization_algEquiv}
1243	  Let \(A\) be a commutative ring and \(x, y \in A\). The fibre product of the two
1244	  basic-open inclusions \(\Spec A[1/x] \to \Spec A \leftarrow \Spec A[1/y]\) is
1245	  canonically isomorphic to the spectrum of the doubly-inverted localisation:
1246	  \[
1247	    \Spec A[1/x] \times_{\Spec A} \Spec A[1/y]
1248	      \;\cong\; \Spec A[1/(xy)].
1249	  \]
1250	  The isomorphism is the composite of the tensor-product identification of the
1251	  pullback (\cref{lem:mathlib_pullbackSpecIso}) with the \(\Spec\) of the
1252	  localisation isomorphism
1253	  \(A[1/x] \otimes_A A[1/y] \cong A[1/(xy)]\)
1254	  (\cref{lem:mathlib_isLocalization_away_mul},
1255	  \cref{lem:mathlib_isLocalization_algEquiv}). It is stated over a general base
1256	  ring \(A\) so that it may be instantiated at the triple-overlap rings of the
1257	  Grassmannian glue datum.
1258	\end{definition}
1259	
1260	\begin{lemma}
1261	
1262	\leanok
1263	[Left leg of the pullback isomorphism]
1264	  \label{lem:gr_awayPullbackIso_inv_fst}
1265	  \lean{AlgebraicGeometry.Grassmannian.awayPullbackIso_inv_fst}
1266	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_left}
1267	  Under the identification of \cref{def:gr_away_pullback_iso}, the first
1268	  projection of the pullback corresponds to the left away-inclusion: the
1269	  composite
1270	  \(\Spec A[1/(xy)] \to \Spec A[1/x] \times_{\Spec A} \Spec A[1/y]
1271	    \xrightarrow{\mathrm{pr}_1} \Spec A[1/x]\)
1272	  equals \(\Spec\) of the inclusion \(\iota^{\mathrm{L}}_{x,y}\)
1273	  (\cref{def:gr_away_incl_left}).
1274	\end{lemma}
1275	\begin{proof}
1276	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_left}
1277	  \leanok
1278	  The pullback-projection compatibility of the tensor-product identification
1279	  sends \(\mathrm{pr}_1\) to the left tensor inclusion, which under the
1280	  localisation isomorphism is the structure map \(A[1/x] \to A[1/(xy)]\), i.e.\
1281	  \(\iota^{\mathrm{L}}_{x,y}\); the verification is the universal property of the
1282	  away-localisation. Proved directly in Lean.
1283	\end{proof}
1284	
1285	\begin{lemma}
1286	
1287	\leanok
1288	[Right leg of the pullback isomorphism]
1289	  \label{lem:gr_awayPullbackIso_inv_snd}
1290	  \lean{AlgebraicGeometry.Grassmannian.awayPullbackIso_inv_snd}
1291	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_right}
1292	  Symmetrically, the second projection of the pullback corresponds to the right
1293	  away-inclusion: the composite
1294	  \(\Spec A[1/(xy)] \to \Spec A[1/x] \times_{\Spec A} \Spec A[1/y]
1295	    \xrightarrow{\mathrm{pr}_2} \Spec A[1/y]\)
1296	  equals \(\Spec\) of \(\iota^{\mathrm{R}}_{x,y}\)
1297	  (\cref{def:gr_away_incl_right}).
1298	\end{lemma}
1299	\begin{proof}
1300	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_right}
1301	  \leanok
1302	  As in \cref{lem:gr_awayPullbackIso_inv_fst}, with the right tensor inclusion in
1303	  place of the left. Proved directly in Lean.
1304	\end{proof}
1305	
1306	\begin{definition}
1307	
1308	\leanok
1309	[Order-swap isomorphism \(A[1/(xy)] \cong A[1/(yx)]\)]
1310	  \label{def:gr_away_mul_comm_equiv}
1311	  \lean{AlgebraicGeometry.Grassmannian.awayMulCommEquiv}
1312	  \uses{lem:mathlib_isLocalization_algEquiv}
1313	  For \(x, y \in A\), the canonical ring isomorphism
1314	  \[
1315	    A[1/(xy)] \;\cong\; A[1/(yx)]
1316	  \]
1317	  identifying the two away-localisations, which agree because \(xy\) and \(yx\)
1318	  generate the same submonoid of \(A\)
1319	  (\cref{lem:mathlib_isLocalization_algEquiv}). It is inserted into the
1320	  triple-cocycle field of the glue datum to reconcile the opposite product
1321	  orders produced by the two pullback isomorphisms.
1322	\end{definition}
1323	
1324	\begin{lemma}
1325	
1326	\leanok
1327	[The order-swap lies over the base ring]
1328	  \label{lem:gr_awayMulCommEquiv_comp_algebraMap}
1329	  \lean{AlgebraicGeometry.Grassmannian.awayMulCommEquiv_comp_algebraMap}
1330	  \uses{def:gr_away_mul_comm_equiv, lem:mathlib_isLocalization_algEquiv}
1331	  The order-swap isomorphism (\cref{def:gr_away_mul_comm_equiv}) intertwines the
1332	  two structure maps: for \(x, y \in A\),
1333	  \[
1334	    \mathrm{swap}_{x,y} \circ \bigl(A \to A[1/(xy)]\bigr)
1335	      \;=\; \bigl(A \to A[1/(yx)]\bigr).
1336	  \]
1337	\end{lemma}
1338	\begin{proof}
1339	  \uses{def:gr_away_mul_comm_equiv, lem:mathlib_isLocalization_algEquiv}
1340	  \leanok
1341	  Both \(A[1/(xy)]\) and \(A[1/(yx)]\) are localisations of \(A\) at the same
1342	  submonoid (\(xy\) and \(yx\) generate it), and the canonical comparison map
1343	  between two such localisations is an \(A\)-algebra isomorphism
1344	  (\cref{lem:mathlib_isLocalization_algEquiv}); an \(A\)-algebra map commutes with
1345	  the structure maps. Proved directly in Lean.
1346	\end{proof}
1347	
1348	\begin{lemma}
1349	[The order-swap absorbs the left inclusion into the right one]
1350	  \label{lem:gr_awayMulCommEquiv_comp_awayInclLeft}
1351	  \lean{AlgebraicGeometry.Grassmannian.awayMulCommEquiv_comp_awayInclLeft}
1352	  \uses{def:gr_away_mul_comm_equiv, def:gr_away_incl_left, def:gr_away_incl_right, lem:gr_awayInclLeft_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:gr_awayInclRight_comp_algebraMap, lem:mathlib_away_lift}
1353	  For \(x, y \in A\), pre-composing the order-swap isomorphism
1354	  \(\mathrm{swap}_{x,y} : A[1/(xy)] \cong A[1/(yx)]\)
1355	  (\cref{def:gr_away_mul_comm_equiv}) with the left away-inclusion
1356	  \(\iota^{\mathrm{L}}_{x,y} : A[1/x] \to A[1/(xy)]\)
1357	  (\cref{def:gr_away_incl_left}) yields the right away-inclusion of the swapped
1358	  pair:
1359	  \[
1360	    \mathrm{swap}_{x,y} \circ \iota^{\mathrm{L}}_{x,y}
1361	      \;=\; \iota^{\mathrm{R}}_{y,x}
1362	      \;:\; A[1/x] \longrightarrow A[1/(yx)] ,
1363	  \]
1364	  where \(\iota^{\mathrm{R}}_{y,x} : A[1/x] \to A[1/(yx)]\) is the right
1365	  away-inclusion (\cref{def:gr_away_incl_right}) for the pair \((y, x)\). This is
1366	  the order-swap coherence used to rotate the triple-overlap transitions.
1367	\end{lemma}
1368	\begin{proof}
1369	  \uses{def:gr_away_mul_comm_equiv, def:gr_away_incl_left, def:gr_away_incl_right, lem:gr_awayInclLeft_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:gr_awayInclRight_comp_algebraMap, lem:mathlib_away_lift}
1370	  Both sides are ring maps out of the away-localisation \(A[1/x]\), so by the
1371	  universal property of the localisation -- the uniqueness of an extension along
1372	  the structure map \(A \to A[1/x]\) (\cref{lem:mathlib_away_lift}) -- it suffices
1373	  to check equality after pre-composing with that structure map, i.e.\ on the base
1374	  ring \(A\). There all three away-maps collapse to structure maps into
1375	  \(A[1/(yx)]\): the left inclusion by
1376	  \cref{lem:gr_awayInclLeft_comp_algebraMap}, the order-swap by
1377	  \cref{lem:gr_awayMulCommEquiv_comp_algebraMap}, and the right inclusion by
1378	  \cref{lem:gr_awayInclRight_comp_algebraMap}. The two composites therefore agree
1379	  on \(A\), hence everywhere. Proved directly in Lean.
1380	\end{proof}
1381	
1382	\subsection*{The triple-overlap glue field \(t'\)}
1383	
1384	The scheme-gluing machine requires, beyond the pairwise transitions \(t_{I,J}\), a
1385	\emph{triple-overlap} field \(t'\) on the relevant fibre products, together with
1386	its compatibility \(t_{\mathrm{fac}}\) with the chart projections. We record both
1387	as the next layer of bridge results; their cocycle coherence is the residual
1388	obligation discharged in \cref{def:gr_glued_scheme}.
1389	
1390	\begin{definition}
1391	
1392	\leanok
1393	[The triple-overlap transition \(t'\)]
1394	  \label{def:gr_chart_transition'}
1395	  \lean{AlgebraicGeometry.Grassmannian.chartTransition'}
1396	  \uses{def:gr_away_pullback_iso, def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv}
1397	  The \(t'\)-field of the Grassmannian glue datum is the morphism of schemes
1398	  \[
1399	    t'_{I,J,K} : U^I_J \times_{U^I} U^I_K \longrightarrow U^J_K \times_{U^J} U^J_I ,
1400	  \]
1401	  defined as the composite
1402	  \[
1403	    U^I_J \times_{U^I} U^I_K
1404	      \xrightarrow{\ \sim\ } \Spec S_I
1405	      \xrightarrow{\ \Spec \Theta_{I,J}\ } \Spec S_J
1406	      \xrightarrow{\ \Spec \mathrm{swap}\ } \Spec R^J[1/(P^J_K P^J_I)]
1407	      \xrightarrow{\ \sim\ } U^J_K \times_{U^J} U^J_I ,
1408	  \]
1409	  where the first and last arrows are the pullback identifications of
1410	  \cref{def:gr_away_pullback_iso} -- the source one for the pair \((P^I_J, P^I_K)\)
1411	  over \(R^I\), and the target one (taken inverse) for the pair \((P^J_K, P^J_I)\)
1412	  over \(R^J\) -- the middle arrow is the \(\Spec\) of the localised
1413	  triple-overlap transition \(\Theta_{I,J} : S_J \to S_I\)
1414	  (\cref{def:gr_cocycle_theta_ij}), and \(\mathrm{swap}\) is the \(\Spec\) of the
1415	  order-swap isomorphism \(R^J[1/(P^J_K P^J_I)] \cong S_J = R^J[1/(P^J_I P^J_K)]\)
1416	  (\cref{def:gr_away_mul_comm_equiv}). The order-swap is inserted precisely to
1417	  reconcile the product order \(P^J_K P^J_I\) carried by the target pullback
1418	  identification with the order \(P^J_I P^J_K\) of the codomain \(S_J\) of
1419	  \(\Theta_{I,J}\).
1420	\end{definition}
1421	
1422	\begin{lemma}
1423	
1424	\leanok
1425	[The \(t'\) ring identity]
1426	  \label{lem:gr_chartTransition'_ringIdentity}
1427	  \lean{AlgebraicGeometry.Grassmannian.chartTransition'_ringIdentity}
1428	  \uses{def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv, def:gr_away_incl_right, def:gr_away_incl_left, def:gr_transition, lem:gr_awayInclRight_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:mathlib_away_lift}
1429	  Over the triple-overlap rings, the localised transition \(\Theta_{I,J}\)
1430	  (\cref{def:gr_cocycle_theta_ij}) pre-composed with the order-swap and the right
1431	  inclusion equals the left inclusion post-composed with the plain transition
1432	  \(\theta_{I,J}\), as ring homomorphisms \(R^J[1/P^J_I] \to S_I\):
1433	  \[
1434	    \Theta_{I,J} \circ \mathrm{swap} \circ \iota^{\mathrm{R}}_{P^J_K, P^J_I}
1435	      \;=\; \iota^{\mathrm{L}}_{P^I_J, P^I_K} \circ \theta_{I,J} .
1436	  \]
1437	\end{lemma}
1438	\begin{proof}
1439	  \uses{def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv, def:gr_away_incl_right, def:gr_away_incl_left, def:gr_transition, lem:gr_awayInclRight_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:mathlib_away_lift}
1440	  \leanok
1441	  Both sides are ring maps out of the away-localisation \(R^J[1/P^J_I]\), so by the
1442	  universal property of the localisation (\cref{lem:mathlib_away_lift}) it suffices
1443	  to check equality after pre-composing with the structure map
1444	  \(R^J \to R^J[1/P^J_I]\), i.e.\ on the chart ring \(R^J\). There the right
