1777	\begin{lemma}
1778	[\(\mathrm{Gr}(r,d)\) is proper over \(\mathbb{Z}\)]
1779	  \label{lem:gr_proper}
1780	  \lean{AlgebraicGeometry.Grassmannian.isProper}
1781	  \uses{def:gr_glued_scheme, lem:gr_separated}
